def insert_node(root, value):
    if root is None:
        return {'value': value, 'left': None, 'right': None}
    if value < root['value']:
        root['left'] = insert_node(root['left'], value)
    elif value > root['value']:
        root['right'] = insert_node(root['right'], value)
    return root

